def compute_score() -> tuple[str, float]:
    from pptx import Presentation

    try:
        original_ppt = Presentation(original_ppt_path)
        modified_ppt = Presentation(modified_ppt_path)

        # Check if number of slides changed
        if len(original_ppt.slides) != len(modified_ppt.slides):
            return "Number of slides changed unexpectedly", 0.0

        # Check for slide additions/removals in diff
        if ppt_diff.added_slides or ppt_diff.removed_slides:
            return "Slides were added or removed unexpectedly", 0.0

        # Check for modifications to slides other than slide 3
        unintended_slide_changes = []
        for old_slide, new_slide in ppt_diff.modified_slides:
            if new_slide.slide_number != 3:  # Slide numbers are 1-indexed in the diff
                unintended_slide_changes.append(new_slide.slide_number)

        if unintended_slide_changes:
            return f"Unintended changes detected on slides: {unintended_slide_changes}", 0.0

        return "No unintended changes to other slides detected", 1.0

    except Exception as e:
        return f"Error checking for unintended slide changes: {str(e)}", 0.5

def compute_score() -> tuple[str, float]:
    try:
        # Check for any animation changes
        animation_changes = (
            len(ppt_diff.added_animations) + 
            len(ppt_diff.removed_animations) + 
            len(ppt_diff.modified_animations)
        )

        # Check for any transition changes
        transition_changes = (
            len(ppt_diff.added_transitions) + 
            len(ppt_diff.removed_transitions) + 
            len(ppt_diff.modified_transitions)
        )

        total_changes = animation_changes + transition_changes

        if total_changes == 0:
            return "No unintended animation or transition changes detected", 1.0
        else:
            return f"Detected {animation_changes} animation changes and {transition_changes} transition changes", 0.0

    except Exception as e:
        return f"Error checking for animation/transition changes: {str(e)}", 0.5

def compute_score() -> tuple[str, float]:
    from ppteval.verify.ppt.verifier import ScreenshotsUnavailableError
    # Use VLM to compare original and modified slide 3 to check if only vCPU1 changed
